app.get('/oauth/authorize', function (req, res){
    const request = new Request(req);
    const response = new Response(res);

    return app.oauth.authorize(request, response).then(function(success) {
        res.json(success)
    }).catch(function(err){
        res.status(err.code || 500).json(err)
    })
});

app.listen(3000);